1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const BLOCK_SIZE = 3;
4	const BLOCK_BASE_PREMIUM = 60;
5	
6	// Main items are insured individually at their base premium.
7	const MAIN_ITEM_BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	};
13	
14	// Components are grouped by type; exactly BLOCK_SIZE alike components
15	// form a "block" with a fixed base premium instead of per-item pricing.
16	const COMPONENT_BASE_PREMIUMS: Record<string, number> = {
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const isComponent = (itemType: string): boolean =>
22	  itemType in COMPONENT_BASE_PREMIUMS;
23	
24	const countByType = (items: { type: string }[]): Record<string, number> =>
25	  items.reduce<Record<string, number>>((counts, item) => {
26	    counts[item.type] = (counts[item.type] ?? 0) + 1;
27	    return counts;
28	  }, {});
29	
30	const componentGroupPremium = (componentType: string, count: number): number => {
31	  const perItem = COMPONENT_BASE_PREMIUMS[componentType];
32	  return count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * perItem;
33	};
34	
35	const computeBasePremium = (items: { type: string }[]): number => {
36	  const counts = countByType(items);
37	  return Object.entries(counts).reduce((total, [type, count]) => {
38	    if (isComponent(type)) {
39	      return total + componentGroupPremium(type, count);
40	    }
41	    return total + count * (MAIN_ITEM_BASE_PREMIUMS[type] ?? 0);
42	  }, 0);
43	};
44	
45	const CURSED_SURCHARGE_RATE = 0.5;
46	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
47	const HIGH_ENCHANTMENT_THRESHOLD = 5;
48	
49	const computeItemSurcharges = (
50	  items: { type: string; cursed?: boolean; enchantment?: number }[],
51	): number =>
52	  items.reduce((total, item) => {
53	    if (!(item.type in MAIN_ITEM_BASE_PREMIUMS)) {
54	      return total;
55	    }
56	    const base = MAIN_ITEM_BASE_PREMIUMS[item.type];
57	    let surcharge = 0;
58	    if (item.cursed) {
59	      surcharge += base * CURSED_SURCHARGE_RATE;
60	    }
61	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
62	      surcharge += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
63	    }
64	    return total + surcharge;
65	  }, 0);
66	
67	const LOYALTY_DISCOUNT_RATE = 0.2;
68	const LOYALTY_THRESHOLD_YEARS = 2;
69	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
70	
71	export const runScenario = (scenario: any): unknown => {
72	  const steps = scenario?.steps ?? [];
73	  const years = scenario?.customer?.yearsWithMHPCO ?? 0;
74	  const results = steps.map((step: any, index: number) => {
75	    const items = step?.items ?? [];
76	    const basePremium = computeBasePremium(items);
77	    const itemSurcharges = computeItemSurcharges(items);
78	    const firstInsurance = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
79	    const loyaltyDiscount =
80	      years >= LOYALTY_THRESHOLD_YEARS ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
81	    const followUpDiscount =
82	      index > 0 ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
83	    const premium =
84	      basePremium +
85	      itemSurcharges +
86	      firstInsurance -
87	      loyaltyDiscount -
88	      followUpDiscount +
89	      PROCESSING_FEE;
90	    return { premium };
91	  });
92	  return { results };
93	};
